import{_ as l,b as r,e as n,al as a}from"./chunks/framework.aXkQZaJg.js";(function(){try{var t=typeof window<"u"?window:typeof global<"u"?global:typeof globalThis<"u"?globalThis:typeof self<"u"?self:{};t.SENTRY_RELEASE={id:"cd437382d5be1b6fdadbf4dbe507c2a9bacaeb41"};var o=new t.Error().stack;o&&(t._sentryDebugIds=t._sentryDebugIds||{},t._sentryDebugIds[o]="1a497fa7-5932-4cb4-9d93-a6f10157615f",t._sentryDebugIdIdentifier="sentry-dbid-1a497fa7-5932-4cb4-9d93-a6f10157615f")}catch{}})();const s="/CoreFront-EndConcepts/img/tcpFirst.png",i="/CoreFront-EndConcepts/img/tcpSecond.png",d="/CoreFront-EndConcepts/img/tcpFifth.png",g="/CoreFront-EndConcepts/img/tcpSixth.png",T=JSON.parse('{"title":"TCP协议","description":"","frontmatter":{},"headers":[],"relativePath":"networkAndBrowsers/protocols/tcp.md","filePath":"networkAndBrowsers/protocols/tcp.md","lastUpdated":1782271806000}'),c={name:"networkAndBrowsers/protocols/tcp.md"};function h(t,o,e,u,_,p){return r(),n("div",null,[...o[0]||(o[0]=[a('<h1 id="tcp协议" tabindex="-1">TCP协议 <a class="header-anchor" href="#tcp协议" aria-label="Permalink to &quot;TCP协议&quot;">​</a></h1><h2 id="_1-什么是-tcp" tabindex="-1">1. 什么是 TCP？ <a class="header-anchor" href="#_1-什么是-tcp" aria-label="Permalink to &quot;1. 什么是 TCP？&quot;">​</a></h2><p><strong>TCP</strong> (Transmission Control Protocol，传输控制协议) 是一种面向连接的、可靠的、基于字节流的<strong>传输层</strong>通信协议。在 OSI 模型中，它位于第四层（传输层），介于应用层（如 HTTP/HTTPS）和网络层（如 IP 协议）之间。</p><p>如果说 IP 协议负责把数据包从地球的一端“尽力而为”地送到另一端（不保证送达），那么 <strong>TCP 协议就是那个负责查收、排队、补发、并最终把完整数据亲手交给应用程序的“快递总管”。</strong></p><h2 id="_2-tcp-的五大核心特性" tabindex="-1">2. TCP 的五大核心特性 <a class="header-anchor" href="#_2-tcp-的五大核心特性" aria-label="Permalink to &quot;2. TCP 的五大核心特性&quot;">​</a></h2><ul><li><strong>面向连接</strong>：通信双方（客户端和服务端）在交换数据之前，必须先建立一条虚拟的逻辑连接。</li><li><strong>可靠传输</strong>：TCP 保证数据能够<strong>无损坏、无丢失、无重复、按序</strong>到达接收端。</li><li><strong>全双工通信</strong>：连接一旦建立，双方都可以同时发送和接收数据。</li><li><strong>面向字节流</strong>：TCP 不关心应用层发来的是什么消息（不管是一张图片还是一段文本），它只把数据看成一连串无结构的字节流。</li><li><strong>流量与拥塞控制</strong>：根据接收方的处理能力和整个网络的拥堵情况，动态调整发送速度。</li></ul><h2 id="_3-tcp-报文段-segment-首部解剖" tabindex="-1">3. TCP 报文段（Segment）首部解剖 <a class="header-anchor" href="#_3-tcp-报文段-segment-首部解剖" aria-label="Permalink to &quot;3. TCP 报文段（Segment）首部解剖&quot;">​</a></h2><p><img src="'+s+'" alt="Logo" data-zoomable="true"></p><p>TCP 首部默认 20 字节，里面藏着 TCP 实现可靠性的所有秘密：</p><ul><li><strong>源端口 / 目的端口 (各 16 位)</strong>：用于定位发送方和接收方的具体应用程序（进程）。</li><li><strong>序号 (Sequence Number, SEQ, 32 位)</strong>：给发送的每一个字节打上编号，解决网络包<strong>乱序</strong>问题，保证接收端能按序重组。</li><li><strong>确认号 (Acknowledgment Number, ACK, 32 位)</strong>：期望收到对方下一个报文段的第一个字节的序号。解决网络包<strong>丢失</strong>问题。</li><li><strong>6 个核心标志位 (Flags)</strong>： <ul><li><strong>SYN (Synchronize)</strong>：用于发起连接。</li><li><strong>FIN (Finish)</strong>：用于释放连接。</li><li><strong>ACK</strong>：确认应答标志，为 1 时确认号才有效。</li><li><strong>RST (Reset)</strong>：强制重置连接（通常在遇到严重错误时使用）。</li><li><strong>PSH (Push)</strong>：催促接收方尽快将数据交付给应用层。</li><li><strong>URG (Urgent)</strong>：紧急指针有效。</li></ul></li></ul><p><img src="'+i+'" alt="Logo" data-zoomable="true"></p><ul><li><strong>窗口大小 (Window Size, 16 位)</strong>：用于<strong>流量控制</strong>，告诉对方“我还能接收多少字节的数据”。</li></ul><h2 id="_4-连接管理-三次握手与四次挥手" tabindex="-1">4. 连接管理：三次握手与四次挥手 <a class="header-anchor" href="#_4-连接管理-三次握手与四次挥手" aria-label="Permalink to &quot;4. 连接管理：三次握手与四次挥手&quot;">​</a></h2><p>这是 TCP 面试必考的绝对核心。</p><h3 id="_4-1-三次握手-建立连接" tabindex="-1">4.1 三次握手 (建立连接) <a class="header-anchor" href="#_4-1-三次握手-建立连接" aria-label="Permalink to &quot;4.1 三次握手 (建立连接)&quot;">​</a></h3><p>目的：同步双方的初始序列号 (ISN)，并确认双方的收发能力正常。</p><ul><li><strong>第一次握手 (C -&gt; S)</strong>：客户端发送 <code>SYN=1, seq=x</code>。（进入 <code>SYN_SENT</code> 状态） <ul><li><em>“你好，我想建立连接，我的初始序列号是 x。”</em></li></ul></li><li><strong>第二次握手 (S -&gt; C)</strong>：服务端收到后，回复 <code>SYN=1, ACK=1, seq=y, ack=x+1</code>。（进入 <code>SYN_RCVD</code> 状态） <ul><li><em>“收到请求，我同意连接。我的初始序列号是 y，期待你发给我的下一个包是 x+1。”</em></li></ul></li><li><strong>第三次握手 (C -&gt; S)</strong>：客户端收到后，回复 <code>ACK=1, seq=x+1, ack=y+1</code>。（双方进入 <code>ESTABLISHED</code> 状态） <ul><li><em>“收到你的确认，连接建立成功，准备发数据！”</em></li></ul></li></ul><p><img src="'+d+'" alt="Logo" data-zoomable="true"></p><h3 id="_4-2-四次挥手-断开连接" tabindex="-1">4.2 四次挥手 (断开连接) <a class="header-anchor" href="#_4-2-四次挥手-断开连接" aria-label="Permalink to &quot;4.2 四次挥手 (断开连接)&quot;">​</a></h3><p>目的：确保双方的数据都已经完整发送和接收完毕。</p><ul><li><strong>第一次挥手 (C -&gt; S)</strong>：客户端数据发完，发送 <code>FIN=1, seq=x</code>。（进入 <code>FIN_WAIT_1</code> 状态） <ul><li><em>“我的数据发完了，请求关闭连接。”</em></li></ul></li><li><strong>第二次挥手 (S -&gt; C)</strong>：服务端收到后，回复 <code>ACK=1, seq=v, ack=x+1</code>。（服务端进入 <code>CLOSE_WAIT</code>，客户端进入 <code>FIN_WAIT_2</code>） <ul><li><em>“收到你的关闭请求。但我可能还有数据没发完，你等我一下。”</em>（此时处于半关闭状态）</li></ul></li><li><strong>第三次挥手 (S -&gt; C)</strong>：服务端数据也发完了，发送 <code>FIN=1, ACK=1, seq=y, ack=v+1</code>。（进入 <code>LAST_ACK</code> 状态） <ul><li><em>“我的数据也全发完了，可以真正关闭了。”</em></li></ul></li><li><strong>第四次挥手 (C -&gt; S)</strong>：客户端收到后，回复 <code>ACK=1, seq=v+1, ack=y+1</code>。（客户端进入 <code>TIME_WAIT</code> 等待 2MSL，服务端收到后进入 <code>CLOSED</code>） <ul><li><em>“好的，再见。”</em></li></ul></li></ul><p><img src="'+g+'" alt="Logo" data-zoomable="true"></p><h2 id="_5-tcp-进阶-如何保证可靠性与高效性" tabindex="-1">5. TCP 进阶：如何保证可靠性与高效性？ <a class="header-anchor" href="#_5-tcp-进阶-如何保证可靠性与高效性" aria-label="Permalink to &quot;5. TCP 进阶：如何保证可靠性与高效性？&quot;">​</a></h2><h3 id="_5-1-滑动窗口与流量控制-flow-control" tabindex="-1">5.1 滑动窗口与流量控制 (Flow Control) <a class="header-anchor" href="#_5-1-滑动窗口与流量控制-flow-control" aria-label="Permalink to &quot;5.1 滑动窗口与流量控制 (Flow Control)&quot;">​</a></h3><ul><li><strong>痛点</strong>：发送方发得太快，接收方缓存满了处理不过来，导致丢包。</li><li><strong>机制</strong>：接收方在每次回复 ACK 时，通过首部的 <code>Window Size</code> 告诉发送方自己剩余的缓存空间。发送方会根据这个窗口大小动态调整发送量。如果窗口为 0，发送方停止发送，并开启定时器发送“窗口探测包”。</li></ul><h3 id="_5-2-拥塞控制四大算法-congestion-control" tabindex="-1">5.2 拥塞控制四大算法 (Congestion Control) <a class="header-anchor" href="#_5-2-拥塞控制四大算法-congestion-control" aria-label="Permalink to &quot;5.2 拥塞控制四大算法 (Congestion Control)&quot;">​</a></h3><p>流量控制是管“点对点”的，拥塞控制是管“整个网络”的。</p><ul><li><strong>慢启动 (Slow Start)</strong>：连接刚建立时，拥塞窗口 (cwnd) 从 1 开始，每收到一个 ACK 就翻倍（指数级增长），快速探明网络上限。</li><li><strong>拥塞避免 (Congestion Avoidance)</strong>：当窗口达到阈值 (ssthresh) 时，变为线性增长（每次加 1），缓慢试探网络拥堵的临界点。</li><li><strong>快速重传 (Fast Retransmit)</strong>：如果接收方收到乱序包，会连续发送 3 个对上一个按序包的重复 ACK。发送方一旦收到 3 个重复 ACK，不等超时，立刻重传丢失的包。</li><li><strong>快速恢复 (Fast Recovery)</strong>：触发快速重传后，TCP 认为网络只是轻微丢包，不会回到慢启动（降为 1），而是将阈值减半，进入拥塞避免阶段。</li></ul><h2 id="_6-终极常见问题-faq-与生产实战排查" tabindex="-1">6. 终极常见问题 (FAQ) 与生产实战排查 <a class="header-anchor" href="#_6-终极常见问题-faq-与生产实战排查" aria-label="Permalink to &quot;6. 终极常见问题 (FAQ) 与生产实战排查&quot;">​</a></h2><h3 id="_6-1-tcp-和-udp-的核心区别是什么" tabindex="-1">6.1 TCP 和 UDP 的核心区别是什么？ <a class="header-anchor" href="#_6-1-tcp-和-udp-的核心区别是什么" aria-label="Permalink to &quot;6.1 TCP 和 UDP 的核心区别是什么？&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">TCP</th><th style="text-align:left;">UDP</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>连接性</strong></td><td style="text-align:left;">面向连接（需握手）</td><td style="text-align:left;">无连接（直接发）</td></tr><tr><td style="text-align:left;"><strong>可靠性</strong></td><td style="text-align:left;">极高（保证不丢包、不乱序）</td><td style="text-align:left;">不可靠（尽力而为，可能丢包）</td></tr><tr><td style="text-align:left;"><strong>速度</strong></td><td style="text-align:left;">较慢（机制复杂，开销大）</td><td style="text-align:left;">极快（机制简单，无延迟）</td></tr><tr><td style="text-align:left;"><strong>适用场景</strong></td><td style="text-align:left;">网页浏览、文件下载、邮件</td><td style="text-align:left;">视频会议、直播、在线游戏、DNS</td></tr><tr><td style="text-align:left;"><strong>优点</strong></td><td style="text-align:left;">稳定、重传机制、拥塞控制机制、断开连接</td><td style="text-align:left;">安全、快速、漏洞少</td></tr><tr><td style="text-align:left;"><strong>缺点</strong></td><td style="text-align:left;">速度慢、效率低、占用资源、容易被攻击（三次握手-&gt;DDOS攻击）</td><td style="text-align:left;">不可靠、不稳定、容易丢包</td></tr></tbody></table><h3 id="_6-2-为什么握手是三次-挥手却是四次" tabindex="-1">6.2 为什么握手是三次，挥手却是四次？ <a class="header-anchor" href="#_6-2-为什么握手是三次-挥手却是四次" aria-label="Permalink to &quot;6.2 为什么握手是三次，挥手却是四次？&quot;">​</a></h3><ul><li><strong>握手三次的原因</strong>：为了防止网络中滞留的“历史失效连接请求”突然到达服务端，导致服务端单方面分配资源（两次握手无法防范此问题）。</li><li><strong>挥手四次的原因</strong>：TCP 是全双工的。客户端发 FIN 只代表客户端不发数据了，但服务端可能还在发数据。所以服务端要先回 ACK，等自己的数据全发完，再发 FIN。中间这两步不能合并。</li></ul><h3 id="_6-3-为什么客户端最后要等待-2msl-time-wait-才能彻底关闭" tabindex="-1">6.3 为什么客户端最后要等待 2MSL (TIME_WAIT) 才能彻底关闭？ <a class="header-anchor" href="#_6-3-为什么客户端最后要等待-2msl-time-wait-才能彻底关闭" aria-label="Permalink to &quot;6.3 为什么客户端最后要等待 2MSL (TIME_WAIT) 才能彻底关闭？&quot;">​</a></h3><ul><li><strong>保证最后的 ACK 能送达</strong>：如果第四次挥手的 ACK 丢了，服务端会重发 FIN。客户端在 2MSL 内可以再次回复 ACK，确保服务端正常关闭。</li><li><strong>清理网络中的残留报文</strong>：让本次连接产生的所有报文在网络中消亡，防止它们去干扰下一个分配了相同端口号的新连接。</li></ul><h3 id="_6-4-生产环境告警-服务器出现海量-time-wait-状态-怎么回事" tabindex="-1">6.4 生产环境告警：服务器出现海量 <code>TIME_WAIT</code> 状态，怎么回事？ <a class="header-anchor" href="#_6-4-生产环境告警-服务器出现海量-time-wait-状态-怎么回事" aria-label="Permalink to &quot;6.4 生产环境告警：服务器出现海量 `TIME_WAIT` 状态，怎么回事？&quot;">​</a></h3><ul><li><strong>原因</strong>：<code>TIME_WAIT</code> 只出现在<strong>主动断开连接的一方</strong>。如果服务器承载大量 HTTP 短连接，且由服务器主动关闭连接，高并发下就会耗尽本地端口（65535 个），导致无法接收新请求。</li><li><strong>解决</strong>：开启长连接（HTTP Keep-Alive）；在 Linux 内核层面调整参数开启 <code>tcp_tw_reuse</code>（允许复用 TIME_WAIT 端口）。</li></ul><h3 id="_6-5-生产环境告警-服务器出现海量-close-wait-状态-怎么回事" tabindex="-1">6.5 生产环境告警：服务器出现海量 <code>CLOSE_WAIT</code> 状态，怎么回事？ <a class="header-anchor" href="#_6-5-生产环境告警-服务器出现海量-close-wait-状态-怎么回事" aria-label="Permalink to &quot;6.5 生产环境告警：服务器出现海量 `CLOSE_WAIT` 状态，怎么回事？&quot;">​</a></h3><ul><li><strong>原因</strong>：<code>CLOSE_WAIT</code> 只出现在<strong>被动关闭的一方</strong>。这 <strong>100% 是业务代码的 Bug</strong>。</li><li><strong>解析</strong>：服务端收到了客户端的 FIN，内核自动回了 ACK，进入 <code>CLOSE_WAIT</code>。但此时，服务端的<strong>业务代码没有调用 <code>close()</code> 函数</strong>来关闭这个 Socket（可能是死锁、异常未捕获等）。导致连接永远卡在这里，最终耗尽文件描述符 (fd) 导致服务宕机。</li></ul><h3 id="_6-6-什么是-tcp-粘包-拆包-如何解决" tabindex="-1">6.6 什么是 TCP 粘包/拆包？如何解决？ <a class="header-anchor" href="#_6-6-什么是-tcp-粘包-拆包-如何解决" aria-label="Permalink to &quot;6.6 什么是 TCP 粘包/拆包？如何解决？&quot;">​</a></h3><ul><li><strong>现象</strong>：TCP 是无边界的字节流。应用层发了两个小包，TCP 可能合并成一个大包发（粘包）；发了一个大包，TCP 可能拆成几个小包发（拆包）。接收端不知道数据的边界在哪。</li><li><strong>解决（应用层负责）</strong>： <ul><li>固定长度消息。</li><li>特殊分隔符（如 HTTP 头的 <code>\\r\\n</code>）。</li><li><strong>消息头+消息体（最常用）</strong>：在头部用几个字节表明后续消息体的长度，接收端按长度读取。</li></ul></li></ul><h3 id="_6-7-如果直接拔掉网线-tcp-连接会立刻断开吗" tabindex="-1">6.7 如果直接拔掉网线，TCP 连接会立刻断开吗？ <a class="header-anchor" href="#_6-7-如果直接拔掉网线-tcp-连接会立刻断开吗" aria-label="Permalink to &quot;6.7 如果直接拔掉网线，TCP 连接会立刻断开吗？&quot;">​</a></h3><ul><li><strong>不会立刻断开</strong>。拔网线是物理层行为，操作系统 TCP 层无法瞬间感知。</li><li>如果双方<strong>正在发数据</strong>，发送方会触发超时重传，重传十几次失败后才会断开。</li><li>如果双方<strong>空闲</strong>，连接会一直保持，直到 TCP Keep-Alive 机制（通常 2 小时）触发探测包，发现不通后才会断开。</li></ul>',43)])])}const f=l(c,[["render",h]]);export{T as __pageData,f as default};
//# sourceMappingURL=networkAndBrowsers_protocols_tcp.md.DhdOk-cE.js.map
